import React from 'react';
import { Link } from 'react-router-dom';

const HomePage = () => {
  return (
    <section>
      <h2>Выбор и экономическое обоснование SaaS-CRM</h2>
      <p>
        Веб-приложение помогает малому бизнесу сравнить Bitrix24, amoCRM и Мегаплан по
        критериям, рассчитать рейтинг и экономическую целесообразность внедрения.
      </p>

      <div className="card-grid">
        <Link className="card" to="/crm">Управление CRM</Link>
        <Link className="card" to="/criteria">Критерии оценки</Link>
        <Link className="card" to="/ratings">Ввод оценок</Link>
        <Link className="card" to="/comparison">Сравнительная таблица</Link>
        <Link className="card" to="/economic">Экономический расчёт</Link>
      </div>
    </section>
  );
};

export default HomePage;
